SELECT COALESCE(SUM(boarding_count + alighting_count), 0) as totalFlow
FROM fact_station_flow
WHERE 1=1

    AND stat_year = #{year}


    AND stat_month = #{month}

SELECT line_name as lineName, SUM(boarding_count + alighting_count) as totalFlow, AVG(load_factor) as avgLoadFactor, COUNT(DISTINCT stop_name) as stationCount FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY line_name ORDER BY totalFlow DESC

SELECT stop_name as stopName, line_name as lineName, SUM(boarding_count + alighting_count) as totalFlow, AVG(load_factor) as avgLoadFactor FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY stop_name, line_name ORDER BY totalFlow DESC
LIMIT #{limit}

SELECT zone_type as zoneType, SUM(boarding_count + alighting_count) as totalFlow, COUNT(DISTINCT stop_name) as stationCount, AVG(load_factor) as avgLoadFactor FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY zone_type ORDER BY totalFlow DESC

SELECT time_period as timePeriod, SUM(boarding_count + alighting_count) as totalFlow, AVG(load_factor) as avgLoadFactor, COUNT(*) as recordCount FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY time_period ORDER BY CASE time_period WHEN '早高峰' THEN 1 WHEN '晚高峰' THEN 2 WHEN '平峰' THEN 3 WHEN '低峰' THEN 4 ELSE 5 END

SELECT line_name as lineName, SUM(boarding_count + alighting_count) as totalFlow, AVG(load_factor) as avgLoadFactor, COUNT(DISTINCT stop_name) as stationCount FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY line_name ORDER BY totalFlow DESC LIMIT 10

SELECT stop_name as stopName, line_name as lineName, SUM(boarding_count + alighting_count) as totalFlow, AVG(load_factor) as avgLoadFactor FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY stop_name, line_name ORDER BY totalFlow DESC LIMIT 10

SELECT AVG(load_factor) as avgLoadFactor
FROM fact_station_flow
WHERE 1=1

    AND stat_year = #{year}


    AND stat_month = #{month}

SELECT AVG(yoy_rate) as yoyRate
FROM fact_station_flow
WHERE 1=1

    AND stat_year = #{year}


    AND stat_month = #{month}

SELECT stat_hour as hour, SUM(boarding_count + alighting_count) as hourlyFlow, AVG(load_factor) as avgLoadFactor FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY stat_hour ORDER BY hourlyFlow DESC LIMIT 5

SELECT line_name as lineName, AVG(load_factor) as avgLoadFactor, MIN(load_factor) as minLoadFactor, MAX(load_factor) as maxLoadFactor FROM fact_station_flow WHERE 1=1
AND stat_year = #{year}
AND stat_month = #{month}
GROUP BY line_name ORDER BY avgLoadFactor DESC
